WITH running_max AS (
  SELECT bucket, close, MAX(close) OVER (ORDER BY bucket ROWS UNBOUNDED PRECEDING) AS peak
  FROM trades_ohlcv_1d
)
SELECT round(min(((close - peak) / peak * 100))::numeric, 2) AS max_drawdown_pct
FROM running_max;

WITH r AS (
  SELECT ln(close/lag(close) OVER (ORDER BY bucket)) AS log_return
  FROM trades_ohlcv_1d
)
SELECT round((avg(log_return) / stddev(log_return) * sqrt(365))::numeric, 2) AS sharpe_ratio
FROM r WHERE log_return IS NOT NULL;

SELECT round(((close - open)/open*100)::numeric,2) AS daily_return_pct
FROM trades_ohlcv_1d
WHERE $__timeFilter(bucket);
